INSERT IGNORE INTO inventarios (cliente_id,producto_id,ubicacion_stock_id,cantidad_disponible,cantidad_reservada,cantidad_minima,cantidad_maxima,updated_at) SELECT 1,p.id,u.id,CASE WHEN u.tipo_ubicacion='ALMACEN' THEN 250 ELSE 60 END,0,CASE WHEN p.id IN (3,4) THEN 100 ELSE 8 END,NULL,NOW() FROM productos p JOIN ubicaciones_stock u ON u.cliente_id=p.cliente_id WHERE p.cliente_id=1;
